/**
 * @fileoverview Milestone component — step/progress indicator.
 *
 * A horizontal or vertical milestone/stepper component for displaying
 * multi-step workflows, progress tracking, or wizard-style navigation.
 *
 * Features:
 *   - Horizontal & vertical layouts
 *   - Step states: completed, active, upcoming, error
 *   - Optional step descriptions
 *   - Icon support (ri-* icon classes or custom content)
 *   - Clickable steps with onSelect callback
 *   - Programmatic API: setActive(), complete(), setError(), reset()
 *   - ARIA accessible
 *
 * HTML pattern:
 *   <div id="my-milestone"></div>
 *
 * @module module/Milestone
 */

import { default as razyui } from '../../index.js';
import { CLS, PART } from './constants.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * @class Milestone
 * @param {string|Element} selector - DOM selector or element.
 * @param {object}  [config]
 * @param {Array}   [config.steps]       - Array of step objects: { title, description?, icon? }
 * @param {number}  [config.active]      - Zero-based index of the active step (default 0)
 * @param {string}  [config.direction]   - 'horizontal' | 'vertical' (default 'horizontal')
 * @param {boolean} [config.clickable]   - Allow clicking steps to navigate (default false)
 * @param {boolean} [config.small]       - Compact size variant (default false)
 * @param {function} [config.onSelect]   - Callback: (index, step) => void
 */
const Milestone = class {
    #el = null;
    #destroyed = false;
    #config = {};
    #steps = [];
    #activeIndex = 0;
    #stepEls = [];
    #eventAC = null;

    constructor(selector, config = {}) {
        const el = razyui.isStr(selector) ? razyui(selector)[0] : selector;
        if (!el) {
            console.warn('Milestone: element not found \u2192', selector);
            return;
        }
        this.#el = el;
        this.#config = {
            steps: [],
            active: 0,
            direction: 'horizontal',
            clickable: false,
            small: false,
            onSelect: null,
            ...config,
        };

        this.#steps = this.#config.steps;
        this.#activeIndex = Math.max(0, Math.min(this.#config.active, this.#steps.length - 1));
        this.#render();
        this.#bindEvents();
    }

    // ────────────────────────────────────────────
    // Rendering
    // ────────────────────────────────────────────

    #render() {
        const $ = razyui;
        const root = $(this.#el);
        root.html('');
        root.addClass(CLS.ROOT);
        if (this.#config.direction === 'vertical') root.addClass(CLS.VERTICAL);
        if (this.#config.small) root.addClass(CLS.SMALL);
        root.attr('role', 'list');
        PART.ROOT.apply(this.#el);

        this.#stepEls = [];

        this.#steps.forEach((step, i) => {
            const stepEl = $.spell('div.' + CLS.STEP, true);
            stepEl.attr('role', 'listitem');
            stepEl.attr('data-index', String(i));
            PART.STEP.apply(stepEl[0]);

            // Connector (between steps)
            if (i > 0) {
                const connector = $.spell('div.' + CLS.CONNECTOR, true);
                if (i <= this.#activeIndex) connector.addClass(CLS.COMPLETED);
                stepEl.append(connector);
            }

            // Marker (circle/icon)
            const marker = $.spell('div.' + CLS.MARKER, true);
            PART.MARKER.apply(marker[0]);
            if (step.icon) {
                marker.html('<i class="' + step.icon + '"></i>');
            } else {
                if (i < this.#activeIndex) {
                    marker.html('<i class="ri-check"></i>');
                } else {
                    marker.text(String(i + 1));
                }
            }
            stepEl.append(marker);

            // Content (title + description)
            const content = $.spell('div.' + CLS.CONTENT, true);
            const title = $.spell('div.' + CLS.TITLE, true);
            title.text(step.title || 'Step ' + (i + 1));
            PART.CONTENT.apply(content[0]);
            PART.TITLE.apply(title[0]);
            content.append(title);

            if (step.description) {
                const desc = $.spell('div.' + CLS.DESC, true);
                desc.text(step.description);
                PART.DESC.apply(desc[0]);
                content.append(desc);
            }
            stepEl.append(content);

            // State classes
            if (i < this.#activeIndex) {
                stepEl.addClass(CLS.COMPLETED);
            } else if (i === this.#activeIndex) {
                stepEl.addClass(CLS.ACTIVE);
                stepEl.attr('aria-current', 'step');
            }

            if (step.error) {
                stepEl.addClass(CLS.ERROR);
            }

            if (this.#config.clickable) {
                stepEl.addClass(CLS.CLICKABLE);
                stepEl.css('cursor', 'pointer');
            }

            this.#stepEls.push(stepEl);
            root.append(stepEl);
        });
    }

    // ────────────────────────────────────────────
    // Events
    // ────────────────────────────────────────────

    #bindEvents() {
        if (!this.#config.clickable) return;

        this.#eventAC = new AbortController();
        const signal = this.#eventAC.signal;

        this.#el.addEventListener('click', (e) => {
            const stepEl = e.target.closest('.' + CLS.STEP);
            if (!stepEl) return;
            const idx = parseInt(stepEl.getAttribute('data-index'));
            if (isNaN(idx) || idx === this.#activeIndex) return;
            this.setActive(idx);
            emitEvent(this.#el, 'select', { index: idx, step: this.#steps[idx] });
            if (typeof this.#config.onSelect === 'function') {
                this.#config.onSelect(idx, this.#steps[idx]);
            }
        }, { signal });
    }

    // ────────────────────────────────────────────
    // State update (without full re-render)
    // ────────────────────────────────────────────

    #updateStates() {
        this.#stepEls.forEach((stepEl, i) => {
            const el = stepEl[0] || stepEl;
            const $el = razyui(el);
            $el.removeClass(CLS.COMPLETED).removeClass(CLS.ACTIVE).removeClass(CLS.ERROR);
            el.removeAttribute('aria-current');

            // Update marker
            const marker = $el.find('.' + CLS.MARKER);
            const step = this.#steps[i];
            if (!step.icon) {
                if (i < this.#activeIndex) {
                    marker.html('<i class="ri-check"></i>');
                } else {
                    marker.text(String(i + 1));
                }
            }

            // Update connector
            const connector = $el.find('.' + CLS.CONNECTOR);
            if (connector.length) {
                if (i <= this.#activeIndex) {
                    connector.addClass(CLS.COMPLETED);
                } else {
                    connector.removeClass(CLS.COMPLETED);
                }
            }

            // Apply state
            if (step.error) {
                $el.addClass(CLS.ERROR);
            } else if (i < this.#activeIndex) {
                $el.addClass(CLS.COMPLETED);
            } else if (i === this.#activeIndex) {
                $el.addClass(CLS.ACTIVE);
                $el.attr('aria-current', 'step');
            }
        });
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /** Set the active step by index. All prior steps become completed. */
    setActive(index) {
        if (index < 0 || index >= this.#steps.length) return;
        this.#steps.forEach(s => { s.error = false; });
        this.#activeIndex = index;
        this.#updateStates();
    }

    /** Mark a specific step as completed and advance active to next. */
    complete(index) {
        if (index === undefined) index = this.#activeIndex;
        if (index < 0 || index >= this.#steps.length) return;
        if (this.#activeIndex <= index && index < this.#steps.length - 1) {
            this.#activeIndex = index + 1;
        }
        this.#updateStates();
    }

    /** Mark a step as having an error. */
    setError(index) {
        if (index === undefined) index = this.#activeIndex;
        if (index < 0 || index >= this.#steps.length) return;
        this.#steps[index].error = true;
        this.#updateStates();
    }

    /** Reset all steps — active goes back to 0. */
    reset() {
        this.#activeIndex = 0;
        this.#steps.forEach(s => { s.error = false; });
        this.#updateStates();
    }

    /** Get current active step index. */
    get active() { return this.#activeIndex; }

    /** Get step data array. */
    get steps() { return this.#steps; }

    getControl() {
        const self = this;
        return {
            setActive:  (i) => self.setActive(i),
            complete:   (i) => self.complete(i),
            setError:   (i) => self.setError(i),
            reset:      ()  => self.reset(),
            get active() { return self.active; },
            get steps()  { return self.steps; },
            destroy:    ()  => self.destroy(),
            get element() { return self.#el; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        razyui(this.#el).html('').removeClass(CLS.ROOT).removeClass(CLS.VERTICAL).removeClass(CLS.SMALL);
    }
};

export default Milestone;
